content:
                 result[j] += raw[pi][j] * 0.2;
                }
            }
            if let Some(ni) = next {
                total_w += 0.2;
                for j in 0..n_bounds {
                    result[j] += raw[ni][j] * 0.2;
                }
            }

            // Re-normalize
            for j in 0..n_bounds {
                result[j] /= total_w;
            }

            // Preserve fixed endpoints: boundary[0] = 0.0, boundary[last] = 1.0
            result[0] = 0.0;
            *result.last_mut().unwrap() = 1.0;

            smoothed[ki] = result;
        }
    }

    smoothed
}
